const topic = $input.first().json.topic;
const payload = $input.first().json.message;
const parts = topic.split('/');
const room = parts[2];
const roomNames = {
  'office': 'Office',
  'livingroom': 'Living Room',
  'bedroom': 'Bedroom',
  'kitchen': 'Kitchen',
  'hallway': 'Hallway'
};
return [{
  json: {
    room,
    roomName: roomNames[room] || room,
    occupied: payload === 'true',
    timestamp: new Date().toISOString(),
    emoji: payload === 'true' ? '🟢' : '⚪'
  }
}];
